void solve(int CASE)
{
	int n; cin >> n;
	string s; cin >> s; s = ' ' + s;

	int ans = 0;
	fa(i, 1, n)ans += s[i] == '1';

	int l = 0, r = 0;
	if (s[1] == '1')l = 1;
	else {
		fa(i, 1, n) {
			if (s[i] == '1') {
				l = i;
				break;
			}
		}
	}

	if (s[n] == '1')r = n;
	else {
		fb(i, n, 1) {
			if (s[i] == '1') {
				r = i;
				break;
			}
		}
	}

	if (l == 0 and r == 0)cout << (n + 2) / 3 << endl;
	else {
		int last = l;
		fa(i, l + 1, r) {
			if (s[i] == '1') {
				int len = i - last - 1 - 2;
				if (len >= 0)
					ans += (len + 2) / 3;
				last = i;
			}
		}
		if (l != 1) {
			int len = l - 1 - 1;
			if (len >= 0)
				ans += (len + 2) / 3;
		}
		if (r != n) {
			int len = n - r - 1;
			if (len >= 0)
				ans += (len + 2) / 3;
		}
		cout << ans << endl;
	}
	return;
}
